checker_dsl:
EXISTS (`TP`) {
  AND {
    EXISTS (`SN`) {
      AND {
        (`SN is a DataFlow::Node`),
        EXISTS (`SBA`) {
          AND {
            (`SBA is an ArrayCreationExpr`),
            (`SBA's array element type is a PrimitiveType with name "byte"`),
            OR {
              (`SBA has no initializer`),
              EXISTS (`AI`) {
                AND {
                  (`AI is the initializer of SBA`),
                  FORALL (`IE`) {
                    AND {
                      (`IE is an element of AI`),
                      OR {
                        (`IE is a CompileTimeConstantExpr`),
                        EXISTS (`NAI`) {
                          AND {
                            (`NAI is an ArrayInit`),
                            (`NAI = IE`),
                            (`NAI satisfies the initializedWithConstantsHelper predicate recursively`)
                          }
                        }
                      }
                    }
                  }
                }
              }
            },
            (`SBA = SN as an expression`),
            NOT {
              EXISTS (`AUS`) {
                AND {
                  (`AUS is a source node in ArrayUpdateFlow`),
                  (`AUS's node as expression = SBA`)
                }
              }
            },
            NOT {
              EXISTS (`RS`) {
                AND {
                  (`RS is a ReturnStmt`),
                  EXISTS (`AD`) {
                    AND {
                      (`AD is a dimension of SBA`),
                      (`AD is a CompileTimeConstantExpr`),
                      (`AD's integer value = 0`)
                    }
                  },
                  EXISTS (`RE`) {
                    AND {
                      (`RE is the expression of RS`),
                      (`there is local data flow from SBA to RE`)
                    }
                  }
                }
              }
            }
          }
        }
      }
    },
    EXISTS (`SK`) {
      AND {
        (`SK is a DataFlow::Node`),
        (`SK is a sink node for encryption-iv`)
      }
    },
    (`there is a taint flow path from SN to SK`)
  }
}
